sp_widget.client_script:
function ClientRequestCtrl($window) {
    /* widget controller */
    var c = this;

    c.form = {
        reporter_name: '',
        reporter_phone: '',
        reporter_email: '',
        hazard_location: '',
        short_description: '',
        description: ''
    };

    c.submitted = false;
    c.data.error = null;
    c.data.successMessage = null;

    c.submitForm = function() {
        if (!c.form.reporter_name) {
            c.data.error = "Full Name is required.";
            return;
        }

        c.data.error = null;

        // Build internal parameters packet payload
        var payload = {
            action: 'submit_hazard_report',
            reporter_name: c.form.reporter_name,
            reporter_phone: c.form.reporter_phone,
            reporter_email: c.form.reporter_email,
            hazard_location: c.form.hazard_location,
            short_description: c.form.short_description,
            description: c.form.description
        };

        // Executes natively over the platform's trusted internal widget data bridge
        c.server.get(payload).then(function(response) {
            if (response && response.data && response.data.success) {
                c.submitted = true;
                c.data.successMessage = "Your hazard report has been received and recorded successfully.";

                // Fire dashboard routing redirect
/*                var redirectUrl = "?id=disaster_status_lookup&" + 
                    "encodedFormName=" + encodeURIComponent(c.form.reporter_name) + 
                    "&encodedPhone=" + encodeURIComponent(c.form.reporter_phone);

                $window.location.href = redirectUrl;
 */
							// Just let the success flags handle the layout state locally
c.submitted = true;
c.data.successMessage = "Thank you! Your report has been submitted successfully. A response team has been dispatched.";
 } else {
                c.data.error = (response && response.data && response.data.error) ? response.data.error : "Submission rejected by system transactional rules.";
            }
        }, function(err) {
            c.data.error = "Internal server communication failure.";
            console.error("Widget Bridge Error: ", err);
        });
    };
}

sp_widget.script:
(function() {
    if (input && input.action === 'submit_hazard_report') {
        try {
            var reporterName   = input.reporter_name || "Anonymous Citizen";
            var reporterEmail  = input.reporter_email || "";
            var reporterPhone  = input.reporter_phone || "";
            var physicalLoc    = input.hazard_location || "";
            var shortDesc      = input.short_description || "Public Community Hazard Report";
            var longDesc       = input.description || "";

            // --- FIXED CROSS-SCOPE SYSTEM INJECTION ---
            var gr = new GlideRecord('x_1834272_emergenc_disaster_assistance_request');
            gr.initialize();

            // Explicitly force the system to bypass client-session security filters natively
            gr.setWorkflow(true); 

            gr.u_citizen_name = reporterName;
            gr.u_citizen_email = reporterEmail;
            gr.u_physical_location = physicalLoc;
            gr.u_summary = shortDesc;

            // Combines the phone and detailed description text area input into u_details for the Business Rule
            gr.u_details = "Contact Phone: " + reporterPhone + "\n\n" +
                           "Detailed Situation Breakdown:\n" + longDesc;

            var incomingAssistance = input.assistance_type ? input.assistance_type.toString() : '';
            var normalizedValue = 'temporary_housing';
            var assignedGroup = 'Disaster Assistance Team';

            if (incomingAssistance === 'temporary_housing' || incomingAssistance === 'Temporary Housing') {
                normalizedValue = 'temporary_housing';
                assignedGroup = 'Disaster Housing Team';
            } else if (incomingAssistance === 'emergency_funding' || incomingAssistance === 'Emergency Funding' || incomingAssistance === 'Financial Assistance') {
                normalizedValue = 'emergency_funding';
                assignedGroup = 'Disaster Finance Team';
            } else if (incomingAssistance === 'food_medical_supplies' || incomingAssistance === 'Food & Supplies' || incomingAssistance === 'Medical Assistance' || incomingAssistance === 'Food/Medical Supplies') {
                normalizedValue = 'food_medical_supplies';
                assignedGroup = 'Disaster Logistics Team';
            }

            gr.u_assistance_type = normalizedValue;
            gr.u_booking_status = 'Pending Staff Verification';
            gr.assignment_group.setDisplayValue(assignedGroup);

            // Commit the row using the custom application's native scope privilege
            var newSysId = gr.insert();

            if (newSysId) {
                data.success = true;
                data.sys_id = newSysId;
            } else {
                data.success = false;
                data.error = "The database rejected the background insertion row. Check Table Access rules.";
            }

        } catch (ex) {
            data.success = false;
            data.error = "Server Script Exception: " + ex.message;
        }

        return; 
    }
})();
